	private static SketchBasedJoinEstimator.Config sketchEstimatorConfig(LmdbStoreConfig config) {
		SketchBasedJoinEstimator.Config estimatorConfig = SketchBasedJoinEstimator.Config.defaults()
				.withThrottleEveryN(config.getSketchEstimatorThrottleEveryN())
				.withThrottleMillis(config.getSketchEstimatorThrottleMillis())
				.withEstimateCacheSeconds(60);
		if (config.getSketchEstimatorSubjectBucketCount() >= 0) {
			estimatorConfig.withSubjectBucketCount(config.getSketchEstimatorSubjectBucketCount());
		}
		if (config.getSketchEstimatorPredicateBucketCount() >= 0) {
			estimatorConfig.withPredicateBucketCount(config.getSketchEstimatorPredicateBucketCount());
		}
		if (config.getSketchEstimatorObjectBucketCount() >= 0) {
			estimatorConfig.withObjectBucketCount(config.getSketchEstimatorObjectBucketCount());
		}
		if (config.getSketchEstimatorContextBucketCount() >= 0) {
			estimatorConfig.withContextBucketCount(config.getSketchEstimatorContextBucketCount());
		}
		estimatorConfig.withContextPairSketchesEnabled(config.getSketchEstimatorContextPairSketchesEnabled());
		return estimatorConfig;
	}

	void rollback() throws SailException {
		sinkStoreAccessLock.lock();
		try {
			try {
				valueStore.rollback();
			} finally {
				if (multiThreadingActive) {
					while (!opQueue.add(ROLLBACK_TRANSACTION)) {
						if (tripleStoreException != null) {
							throw wrapTripleStoreException();
						} else {
							Thread.yield();
						}
					}
				} else {
					tripleStore.rollback();
				}
			}
		} catch (Exception e) {
			logger.warn("Failed to rollback LMDB transaction", e);
			throw e instanceof SailException ? (SailException) e : new SailException(e);
		} finally {
			tripleStoreException = null;
			discardEstimatorStateTouchedByOpenTransaction();
			storeTxnStarted.set(false);
			sinkStoreAccessLock.unlock();
		}
	}

	private void discardEstimatorStateTouchedByOpenTransaction() {
		if (estimatorTouchedSinceStoreTxnStart.getAndSet(false) && sketchBasedJoinEstimator != null) {
			sketchBasedJoinEstimator.discardAndMarkForRebuild();
		}
	}

	@Override
	public void close() throws SailException {
		try {
			try {
				cancelAndDrainScheduledBackgroundSampling();
				cancelAndDrainScheduledEstimatorPersist();
				shutdownAndAwaitEstimatorPersistExecutor();
				if (sketchBasedJoinEstimator != null) {
					sketchBasedJoinEstimator.close();
				}
				if (filterSelectivityStats != null) {
					filterSelectivityStats.persistIfDirty();
				}
			} finally {
				try {
					if (namespaceStore != null) {
						namespaceStore.close();
					}
				} finally {
					try {
						if (valueStore != null) {
							valueStore.close();
						}
					} finally {
						try {
							if (tripleStore != null) {
								try {
									running.set(false);
									tripleStoreExecutor.shutdown();
									try {
										while (!tripleStoreExecutor.awaitTermination(1, TimeUnit.SECONDS)) {
											logger.warn("Waiting for triple store executor to terminate");
										}
									} catch (InterruptedException e) {
										Thread.currentThread().interrupt();
										throw new InterruptedSailException(e);
									}
								} finally {
									shutdownAndAwaitEstimatorPersistExecutor();
									tripleStore.close();
								}
							}
						} finally {
							if (setFactory != null) {
								setFactory.close();
								setFactory = null;
							}
						}
					}
				}
			}
		} catch (IOException e) {
			logger.warn("Failed to close store", e);
			throw new SailException(e);
		}
	}

	private void shutdownAndAwaitEstimatorPersistExecutor() {
		estimatorPersistExec.shutdown();
		try {
			while (!estimatorPersistExec.awaitTermination(1, TimeUnit.SECONDS)) {
				logger.warn("Waiting for join estimator persist executor to terminate");
			}
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new InterruptedSailException(e);
		}
	}

	private void cancelAndDrainScheduledBackgroundSampling() {
		ScheduledFuture<?> future = backgroundSamplingFuture;
		if (future == null) {
			return;
		}
		if (future.cancel(false)) {
			return;
		}
		try {
			future.get();
		} catch (CancellationException e) {
			// Already cancelled by the scheduler or another close path.
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new InterruptedSailException(e);
		} catch (ExecutionException e) {
			logger.warn("Scheduled background filter sampling failed during close", e.getCause());
		}
	}

	private void cancelAndDrainScheduledEstimatorPersist() {
		ScheduledFuture<?> future = persistFuture;
		if (future == null) {
			return;
		}
		if (future.cancel(false)) {
			return;
		}
		try {
			future.get();
		} catch (CancellationException e) {
			// Already cancelled by the scheduler or another close path.
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new InterruptedSailException(e);
		} catch (ExecutionException e) {
			logger.warn("Scheduled join estimator persistence failed during close", e.getCause());
		}
	}

	private void startBackgroundFilterSampling() {
		if (filterSelectivityStats == null || backgroundRawSamplingMaxMillisPerCycle <= 0L) {
			logger.info(
					"LMDB background filter sampling not scheduled: filterStatsPresent={}, maxMillisPerCycle={}",
					filterSelectivityStats != null, backgroundRawSamplingMaxMillisPerCycle);
			return;
		}
		logger.info(
				"LMDB background filter sampling scheduled: initialDelayMillis={}, delayMillis={}, maxMillisPerCycle={}",
				estimatorPersistDelayMillis, estimatorPersistDelayMillis, backgroundRawSamplingMaxMillisPerCycle);
		backgroundSamplingFuture = estimatorPersistExec.scheduleWithFixedDelay(() -> {
			try {
				runBackgroundFilterSamplingCycle(backgroundRawSamplingMaxMillisPerCycle);
			} catch (RuntimeException e) {
				logger.warn("Background filter sampling cycle failed", e);
			}
		}, estimatorPersistDelayMillis, estimatorPersistDelayMillis, TimeUnit.MILLISECONDS);
	}

	int runBackgroundFilterSamplingCycle(long maxMillis) {
		if (filterSelectivityStats == null || maxMillis <= 0L) {
			logger.info(
					"LMDB background filter sampling cycle skipped: filterStatsPresent={}, maxMillis={}",
					filterSelectivityStats != null, maxMillis);
			return 0;
		}
		int pendingRequests = filterSelectivityStats.pendingBackgroundSamplingRequests();
		if (storeTxnStarted.get()) {
			if (pendingRequests > 0) {
				logger.info(
						"LMDB background filter sampling cycle skipped: store transaction active, pendingRequests={}",
						pendingRequests);
			}
			return 0;
		}
		if (!sinkStoreAccessLock.tryLock()) {
			if (pendingRequests > 0) {
				logger.info(
						"LMDB background filter sampling cycle skipped: sink store access lock unavailable, pendingRequests={}",
						pendingRequests);
			}
			return 0;
		}
		try {
			if (storeTxnStarted.get()) {
				if (pendingRequests > 0) {
					logger.info(
							"LMDB background filter sampling cycle skipped: store transaction started after lock, pendingRequests={}",
							pendingRequests);
				}
				return 0;
			}
			int sampled = filterSelectivityStats.runBackgroundSamplingCycle(maxMillis);
			if (sampled > 0) {
				scheduleEstimatorPersist();
			}
			return sampled;
		} finally {
			sinkStoreAccessLock.unlock();
		}
	}

	private void persistEstimatorState() {
		if (sketchBasedJoinEstimator != null) {
			sketchBasedJoinEstimator.persistIfDirty();
		}
		if (filterSelectivityStats != null) {
			filterSelectivityStats.persistIfDirty();
		}
	}

	private void scheduleEstimatorPersist() {
		if (persistScheduled.compareAndSet(false, true)) {
			persistFuture = estimatorPersistExec.schedule(() -> {
				try {
					LmdbSailStore.this.persistEstimatorState();
				} finally {
					persistScheduled.set(false);
				}
			}, estimatorPersistDelayMillis, TimeUnit.MILLISECONDS);
		}
	}

	SailException wrapTripleStoreException() {
		return tripleStoreException instanceof SailException ? (SailException) tripleStoreException
				: new SailException(tripleStoreException);
	}

